#!/usr/bin/env bash
set -Eeuo pipefail

TARGET_DIR="${1:-$HOME/android-context-intelligence}"
echo "[Permission Graph v0.1] Installing to $TARGET_DIR..."

mkdir -p "$TARGET_DIR"
cd "$TARGET_DIR"

echo "Extracting payload files..."
mkdir -p "$(dirname "workspace/languages.py")"
base64 -d > "workspace/languages.py" << 'PAYLOAD'

PAYLOAD

mkdir -p "$(dirname "config/parser_registry.toml")"
base64 -d > "config/parser_registry.toml" << 'PAYLOAD'

PAYLOAD

mkdir -p "$(dirname "workspace/multi_permission.py")"
base64 -d > "workspace/multi_permission.py" << 'PAYLOAD'

PAYLOAD

mkdir -p "$(dirname "collectors/permission/__init__.py")"
base64 -d > "collectors/permission/__init__.py" << 'PAYLOAD'
IyBwZXJtaXNzaW9uIGNvbGxlY3RvcnMK
PAYLOAD

mkdir -p "$(dirname "collectors/permission/xml_permission_importer.py")"
base64 -d > "collectors/permission/xml_permission_importer.py" << 'PAYLOAD'

PAYLOAD

mkdir -p "$(dirname "collectors/permission/java_permission_scanner.py")"
base64 -d > "collectors/permission/java_permission_scanner.py" << 'PAYLOAD'

PAYLOAD

mkdir -p "$(dirname "scripts/rebuild_all.sh")"
base64 -d > "scripts/rebuild_all.sh" << 'PAYLOAD'

PAYLOAD


echo "Setting permissions..."
chmod +x scripts/rebuild_all.sh

echo "Installation complete!"
echo "You can now run: ./scripts/rebuild_all.sh"
